function initHeaderScroll(){const e=document.querySelector(".header");if(!e)return;const t=()=>{window.scrollY>50?e.classList.add("header--scrolled"):e.classList.remove("header--scrolled")};window.addEventListener("scroll",t,{passive:!0}),t()}function initFeatureTabs(){const e=document.querySelectorAll(".features__tab"),t=document.querySelectorAll(".features__panel"),a=document.querySelector(".features__preview-img");e.length&&t.length&&e.forEach(o=>{o.addEventListener("click",()=>{if(o.classList.contains("features__tab--active"))return;const r=o.dataset.tab,c=o.dataset.image;e.forEach(e=>e.classList.remove("features__tab--active")),o.classList.add("features__tab--active"),t.forEach(e=>e.classList.remove("features__panel--active"));const n=document.querySelector(`[data-panel="${r}"]`);n&&n.classList.add("features__panel--active"),a&&c&&(a.style.opacity="0",setTimeout(()=>{a.src=c,a.setAttribute("data-image",r),a.style.opacity="1"},200))})})}function initSmoothScroll(){document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener("click",t=>{const a=e.getAttribute("href");if("#"===a||"#!"===a)return;const o=document.querySelector(a);if(o){t.preventDefault();const e=document.querySelector(".header")?.offsetHeight||72,a=o.getBoundingClientRect().top+window.scrollY-e;window.scrollTo({top:a,behavior:"smooth"})}})})}function initMobileMenu(){const e=document.querySelector(".header__hamburger"),t=document.querySelector(".header__nav"),a=document.querySelector(".header__actions");e&&e.addEventListener("click",()=>{e.classList.toggle("header__hamburger--active"),t?.classList.toggle("header__nav--open"),a?.classList.toggle("header__actions--open")})}document.addEventListener("DOMContentLoaded",()=>{initHeaderScroll(),initFeatureTabs(),initSmoothScroll(),initMobileMenu()});